var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"날 거둬준 사람의 직통 회선이야.","JPN":"私を拾ってくれた人に直通で繋がる回線だ。","ENG":"This is a direct line to the one who took me in.","TWN":"這是我和收留我的那個人的專線。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그리고 이곳으로 보낸 장본인이기도 하지.","JPN":"私をここに送った人でもある。","ENG":"And the very person who sent me here.","TWN":"而且也是把我送到這裡的人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저택을 빠져나간다면 어떻게든 그 사람한테 연락해.","JPN":"邸宅の外に出たら、なんとしてもその人に連絡して。","ENG":"If you make it out of the estate, contact her no matter what.","TWN":"如果你能逃出這座屋子，不管怎樣都要聯絡那個人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"좀 장난이 심하긴 하지만…… 어떻게든 도와줄 거야.","JPN":"ちょっといたずら好きな人だけど……どうにかしてくれるはずだから。","ENG":"She might be joking around a bit much, but... she'll help.","TWN":"雖然她愛開玩笑……但她還是會幫忙的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"잠시만요!","JPN":"ちょっと待ってください！","ENG":"Wait a second!","TWN":"等下！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무슨 유언이라도 남기려는 듯이 말씀하시네요.","JPN":"まるで遺言みたいな物言いじゃないですか。","ENG":"You're talking like you're leaving some final words!","TWN":"你說話的樣子好像要留下什麼遺言似的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"지금 절 내보내고 본인이 여기 남겠다는 거예요?","JPN":"私を逃がして、自分はここに残るってことですか？","ENG":"Are you seriously planning to stay behind while I escape?!","TWN":"現在要把我放出去，自己留在這裡嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이건 자살 행위예요! 분명 당신은 여기서……!","JPN":"自殺行為ですよ！　たぶんあなたはここで……！","ENG":"That's suicide! There's no way you'll make it out of here...!","TWN":"你這無異於自殺！你肯定會在這裡……！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"나는 돈 떼 먹히는 건 질색이야.","JPN":"私は、代金を踏み倒されるのは大っ嫌いなんだよ。","ENG":"I can't stand getting scammed out of my pay.","TWN":"我最討厭被人欠錢了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저 자식한테 의뢰비 받을 때까진 여기 안 떠나.","JPN":"あいつから報酬をもらうまで、ここから一歩も動かないから。","ENG":"I'm not leaving until I collect my fee from that jerk.","TWN":"在從那傢伙那裡拿到委託費之前，我不會離開這裡。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그, 그런 억지가……!","JPN":"そ、そんな無茶な……！！","ENG":"Th-that's absurd...!","TWN":"還，還在嘴硬……！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"나도 다 병을 치료하려고 돈 버는 거라고.","JPN":"私だって、病気を治療するために金を稼いでるんだ。","ENG":"I'm just trying to make enough money to cure my sickness.","TWN":"我是為了治病才要賺錢的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"큰돈 벌 수 있는 기회를 놓칠 순 없어.","JPN":"大金を稼ぐチャンスを逃すわけにはいかないんだよ。","ENG":"I can't afford to let a payday this big slip away.","TWN":"不能錯過賺大錢的機會。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 상황에서도 돈 얘기예요?!","JPN":"この期に及んでもお金の話ですか！？","ENG":"You're still thinking about money at a time like this?!","TWN":"這種情況下還談錢嗎？!"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"원래 이런 진로 상담도 다 돈을 받아내는 법인데.","JPN":"本当は、こういう進路相談も全部代金を取るんだけど……","ENG":"Counseling sessions like this usually come with a service fee.","TWN":"原本這種職業諮詢都是要收費的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이걸로 나 살려준 빚은 갚았다?","JPN":"これで助けてもらった借りはチャラだからね。","ENG":"Consider your debt paid.","TWN":"這樣我就還清了你救我的恩情了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……알겠어요.","JPN":"……わかりました。","ENG":"...Fine.","TWN":"……知道了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"꼭…… 살아 있어야 해요.","JPN":"絶対……生きててください。","ENG":"You... have to survive.","TWN":"一定要活下去。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"제가 어떻게든 당신을 구하러 올 테니까.","JPN":"なんとかしてあなたを助けに来ます。","ENG":"No matter what, I'll come back for you.","TWN":"我一定會來救你的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"주님에게…… 맹세할게요.","JPN":"主の御名にかけて……誓います。","ENG":"I swear it... before the Lord.","TWN":"我向你……發誓。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"더 말하면 추가 요금 청구한다.","JPN":"それ以上言うと、追加料金だよ。","ENG":"Say one more word, and I'm charging you extra.","TWN":"再多說一句就要加收費用了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"얼른 가.","JPN":"早く行きな。","ENG":"Now go.","TWN":"快點走。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"창백한 달 감염자는 나중에 잡아도 상관없네.","JPN":"青白い月の感染者は後で捕らえても構わない。","ENG":"The Pale Moon afflicted can wait. I can always catch her later.","TWN":"蒼月感染者以後再抓也沒關係。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"이 넓은 영지를 벗어나 봤자 얼마나 벗어나겠나?","JPN":"この広い領地から逃げようとしたところで、そう遠くまでは行けないはずだ。","ENG":"Considering how vast my estate is, she won't get far.","TWN":"就算離開這片廣闊的領地，又能走多遠呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그런데도 이 미련한 싸움을 하려는 이유가 뭐지?","JPN":"それでもこの愚かな戦いを続ける理由は何かね？","ENG":"So why bother with this foolish struggle?","TWN":"即便如此，為什麼還要進行這場愚蠢的戰鬥？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"지려고 싸우는 바보가 어딨냐.","JPN":"負けるつもりで戦うバカはいないよ。","ENG":"Who fights to lose?","TWN":"哪有為了輸而戰的傻瓜。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어떻게든 이기려고 발버둥 치는 거지.","JPN":"なんとか勝つために足掻くだけ。","ENG":"I'm struggling because I want to win.","TWN":"無論如何都要掙扎著贏。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L42_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"흥미롭군.","JPN":"興味深い。","ENG":"Interesting.","TWN":"真有趣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"어디 한번 발버둥 쳐보게.","JPN":"ならば、好きなだけ足掻いてみるといい。","ENG":"Then by all means, struggle.","TWN":"儘管掙扎吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그러는 편이 나에게도 재밌을 테니.","JPN":"そのほうが、私にとっても面白い。","ENG":"It'll make things far more entertaining for me.","TWN":"這樣對我來說也會更有趣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"모욕적인 언사.","JPN":"侮辱的な発言。","ENG":"Insulting remarks.","TWN":"侮辱性的言辭。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_7-2"},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"반인륜적인 실험.","JPN":"倫理に反する実験。","ENG":"Inhumane experiments.","TWN":"反人類的實驗。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_8"},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"가장 중요한…… 의뢰금 미납.","JPN":"なにより……依頼料の不払い。","ENG":"And worst of all... unpaid contract fees.","TWN":"最重要的……委託金未支付。"},"stage":{"bg":"MOONLIGHT_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_9"},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 침식체들 전부 박살 내고 나면.","JPN":"この侵食体を全部ぶちのめしたら……","ENG":"Once I tear through these C.O.s.","TWN":"等我打爆這些侵蝕體後"},"stage":{"bg":"MOONLIGHT_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_10-2"},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"반드시 네 머리통도 박살 낸다.","JPN":"次はあなたの頭をぶち壊す。","ENG":"I'm coming to crush that head of yours.","TWN":"一定會打爆你的腦袋"},"stage":{"bg":"MOONLIGHT_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_11"},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……주님한테 맹세하지.","JPN":"……主の御名に誓って。","ENG":"...I swear by it on the Lord.","TWN":"……我向主發誓。"},"stage":{"bg":"MOONLIGHT_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_12-2"},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 물론 내 주님은 주식 님이야.","JPN":"ああ、もちろん私の主は金だけどね。","ENG":"Oh, and just to be clear, the only \\"Lord\\" I believe in is money.","TWN":"不過，我的主當然是指股票囉"},"stage":{"bg":"MOONLIGHT_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_13-2"},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무신론자라서.","JPN":"無神論者なんで。","ENG":"I'm an atheist, you see.","TWN":"因為我可是無神論者"},"stage":{"bg":"MOONLIGHT_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_BLUE_IN_TRAILER_14-2"},{"id":"L15_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"이참에 나도 최대한 많은 데이터를 수집해야겠어.","JPN":"これを機に私もなるべく多くのデータを集めたいものだ。","ENG":"Then I should take this opportunity to collect as much data as possible.","TWN":"趁這個機會，我也要盡可能多地收集資料。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네 같은 자들이 얼마나 버틸 수 있는지 궁금하거든.","JPN":"君のような者たちが、どこまで耐えられるか興味がある。","ENG":"I'm curious how long someone like you can hold out.","TWN":"我很好奇像你這樣的人能堅持多久。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"각오하게. 나는 실험을 깐깐하게 하는 편이니.","JPN":"覚悟したまえ。私は実験についてはうるさいほうだぞ。","ENG":"Brace yourself. I conduct my experiments very thoroughly.","TWN":"做好準備吧。我可是對實驗非常嚴格的人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};